import{_ as t,o as a,c as r,ae as n}from"./chunks/framework.BvHJbMD4.js";const p=JSON.parse('{"title":"2024-11-14","description":"","frontmatter":{},"headers":[],"relativePath":"2024-11/2024-11-14.md","filePath":"2024-11/2024-11-14.md"}'),i={name:"2024-11/2024-11-14.md"};function o(d,e,s,l,h,g){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="_2024-11-14" tabindex="-1">2024-11-14 <a class="header-anchor" href="#_2024-11-14" aria-label="Permalink to &quot;2024-11-14&quot;">​</a></h1><h2 id="cs-ar-architecture" tabindex="-1">cs.AR - Architecture <a class="header-anchor" href="#cs-ar-architecture" aria-label="Permalink to &quot;cs.AR - Architecture&quot;">​</a></h2><table tabindex="0"><thead><tr><th>标题</th><th>作者</th><th>发布日期</th><th>PDF</th><th>摘要</th></tr></thead><tbody><tr><td><a href="https://arxiv.org/abs/2411.09760v1" target="_blank" rel="noreferrer">SpecPCM: A Low-power PCM-based In-Memory Computing Accelerator for Full-stack Mass Spectrometry Analysis</a></td><td>Keming Fan, Ashkan Moradifirouzabadi, Xiangjin Wu, Zheyu Li, Flavio Ponzina, Anton Persson, Eric Pop, Tajana Rosing, Mingu Kang</td><td>2024-11-14</td><td><a href="https://arxiv.org/pdf/2411.09760v1.pdf" target="_blank" rel="noreferrer">下载</a></td><td>Mass spectrometry (MS) is essential for proteomics and metabolomics but faces impending challenges in efficiently processing the vast volumes of data.</td></tr><tr><td><a href="https://arxiv.org/abs/2411.09546v1" target="_blank" rel="noreferrer">Architectural Exploration of Application-Specific Resonant SRAM Compute-in-Memory (rCiM)</a></td><td>Dhandeep Challagundla, Ignatius Bezzam, Riadul Islam</td><td>2024-11-14</td><td><a href="https://arxiv.org/pdf/2411.09546v1.pdf" target="_blank" rel="noreferrer">下载</a></td><td>While general-purpose computing follows Von Neumann&#39;s architecture, the data movement between memory and processor elements dictates the processor&#39;s performance.</td></tr><tr><td><a href="https://arxiv.org/abs/2411.09543v2" target="_blank" rel="noreferrer">OpenGeMM: A High-Utilization GeMM Accelerator Generator with Lightweight RISC-V Control and Tight Memory Coupling</a></td><td>Xiaoling Yi, Ryan Antonio, Joren Dumoulin, Jiacong Sun, Josse Van Delm, Guilherme Paim, Marian Verhelst</td><td>2024-11-14</td><td><a href="https://arxiv.org/pdf/2411.09543v2.pdf" target="_blank" rel="noreferrer">下载</a></td><td>Deep neural networks (DNNs) face significant challenges when deployed on resource-constrained extreme edge devices due to their computational and data-intensive nature.</td></tr><tr><td><a href="https://arxiv.org/abs/2411.09315v1" target="_blank" rel="noreferrer">Sustainable Hardware Specialization</a></td><td>Pranav Dangi, Thilini Kaushalya Bandara, Saeideh Sheikhpour, Tulika Mitra, Lieven Eeckhout</td><td>2024-11-14</td><td><a href="https://arxiv.org/pdf/2411.09315v1.pdf" target="_blank" rel="noreferrer">下载</a></td><td>Hardware specialization is commonly viewed as a way to scale performance in the dark silicon era with modern-day SoCs featuring multiple tens of dedicated accelerators.</td></tr><tr><td><a href="https://arxiv.org/abs/2411.09201v1" target="_blank" rel="noreferrer">Noncontact Multi-Point Vital Sign Monitoring with mmWave MIMO Radar</a></td><td>Wei Ren, Jiannong Cao, Huansheng Yi, Kaiyue Hou, Miaoyang Hu, Jianqi Wang, Fugui Qi</td><td>2024-11-14</td><td><a href="https://arxiv.org/pdf/2411.09201v1.pdf" target="_blank" rel="noreferrer">下载</a></td><td>Multi-point vital sign monitoring is essential for providing detailed insights into physiological changes. Traditional single-sensor approaches are inadequate for capturing multi-point vibrations.</td></tr><tr><td><a href="https://arxiv.org/abs/2411.09159v1" target="_blank" rel="noreferrer">PIMCOMP: An End-to-End DNN Compiler for Processing-In-Memory Accelerators</a></td><td>Xiaotian Sun, Xinyu Wang, Wanqian Li, Yinhe Han, Xiaoming Chen</td><td>2024-11-14</td><td><a href="https://arxiv.org/pdf/2411.09159v1.pdf" target="_blank" rel="noreferrer">下载</a></td><td>Various processing-in-memory (PIM) accelerators based on various devices, micro-architectures, and interfaces have been proposed to accelerate deep neural networks (DNNs).</td></tr></tbody></table><h2 id="cs-dc-distributed-parallel-and-cluster-computing" tabindex="-1">cs.DC - Distributed, Parallel, and Cluster Computing <a class="header-anchor" href="#cs-dc-distributed-parallel-and-cluster-computing" aria-label="Permalink to &quot;cs.DC - Distributed, Parallel, and Cluster Computing&quot;">​</a></h2><table tabindex="0"><thead><tr><th>标题</th><th>作者</th><th>发布日期</th><th>PDF</th><th>摘要</th></tr></thead><tbody><tr><td><a href="https://arxiv.org/abs/2411.09809v1" target="_blank" rel="noreferrer">Scalable Readability Evaluation for Graph Layouts: 2D Geometric Distributed Algorithms</a></td><td>Sanggeon Yun</td><td>2024-11-14</td><td><a href="https://arxiv.org/pdf/2411.09809v1.pdf" target="_blank" rel="noreferrer">下载</a></td><td>Graphs, consisting of vertices and edges, are vital for representing complex relationships in fields like social networks, finance, and blockchain.</td></tr><tr><td><a href="https://arxiv.org/abs/2411.09473v1" target="_blank" rel="noreferrer">Enhancing Scalability and Performance in Influence Maximization with Optimized Parallel Processing</a></td><td>Hanjiang Wu, Huan Xu, Joongun Park, Jesmin Jahan Tithi, Fabio Checconi, Jordi Wolfson-Pou, Fabrizio Petrini, Tushar Krishna</td><td>2024-11-14</td><td><a href="https://arxiv.org/pdf/2411.09473v1.pdf" target="_blank" rel="noreferrer">下载</a></td><td>Influence Maximization (IM) is vital in viral marketing and biological network analysis for identifying key influencers. Given its NP-hard nature, approximate solutions are employed.</td></tr><tr><td><a href="https://arxiv.org/abs/2411.09317v1" target="_blank" rel="noreferrer">Pie: Pooling CPU Memory for LLM Inference</a></td><td>Yi Xu, Ziming Mao, Xiangxi Mo, Shu Liu, Ion Stoica</td><td>2024-11-14</td><td><a href="https://arxiv.org/pdf/2411.09317v1.pdf" target="_blank" rel="noreferrer">下载</a></td><td>The rapid growth of LLMs has revolutionized natural language processing and AI analysis, but their increasing size and memory demands present significant challenges.</td></tr><tr><td><a href="https://arxiv.org/abs/2411.09275v2" target="_blank" rel="noreferrer">Parallel $k$d-tree with Batch Updates</a></td><td>Ziyang Men, Zheqi Shen, Yan Gu, Yihan Sun</td><td>2024-11-14</td><td><a href="https://arxiv.org/pdf/2411.09275v2.pdf" target="_blank" rel="noreferrer">下载</a></td><td>The $k$d-tree is one of the most widely used data structures to manage multi-dimensional data. Due to the ever-growing data volume, it is imperative to consider parallelism in $k$d-trees.</td></tr></tbody></table><h2 id="cs-ni-networking-and-internet-architecture" tabindex="-1">cs.NI - Networking and Internet Architecture <a class="header-anchor" href="#cs-ni-networking-and-internet-architecture" aria-label="Permalink to &quot;cs.NI - Networking and Internet Architecture&quot;">​</a></h2><table tabindex="0"><thead><tr><th>标题</th><th>作者</th><th>发布日期</th><th>PDF</th><th>摘要</th></tr></thead><tbody><tr><td><a href="https://arxiv.org/abs/2411.09849v1" target="_blank" rel="noreferrer">Self-Supervised Radio Pre-training: Toward Foundational Models for Spectrogram Learning</a></td><td>Ahmed Aboulfotouh, Ashkan Eshaghbeigi, Dimitrios Karslidis, Hatem Abou-Zeid</td><td>2024-11-14</td><td><a href="https://arxiv.org/pdf/2411.09849v1.pdf" target="_blank" rel="noreferrer">下载</a></td><td>Foundational deep learning (DL) models are general models, trained on large, diverse, and unlabelled datasets, typically using self-supervised learning techniques have led to significant advancements ...</td></tr><tr><td><a href="https://arxiv.org/abs/2411.09812v1" target="_blank" rel="noreferrer">Edge Caching Optimization with PPO and Transfer Learning for Dynamic Environments</a></td><td>Farnaz Niknia, Ping Wang</td><td>2024-11-14</td><td><a href="https://arxiv.org/pdf/2411.09812v1.pdf" target="_blank" rel="noreferrer">下载</a></td><td>This paper addresses the challenge of edge caching in dynamic environments, where rising traffic loads strain backhaul links and core networks.</td></tr><tr><td><a href="https://arxiv.org/abs/2411.09660v1" target="_blank" rel="noreferrer">Capacity and Power Consumption of Multi-Layer 6G Networks Using the Upper Mid-Band</a></td><td>David López-Pérez, Nicola Piovesan, Giovanni Geraci</td><td>2024-11-14</td><td><a href="https://arxiv.org/pdf/2411.09660v1.pdf" target="_blank" rel="noreferrer">下载</a></td><td>This paper presents a new system model to evaluate the capacity and power consumption of multi-layer 6G networks utilising the upper mid-band (FR3).</td></tr><tr><td><a href="https://arxiv.org/abs/2411.18633v1" target="_blank" rel="noreferrer">Geospatial sustainability assessment of universal Fiber-To-The-Neighborhood (FTTnb) broadband infrastructure strategies for Sub-Saharan Africa</a></td><td>Ogutu B. Osoro, Edward J. Oughton, Fabion Kauker</td><td>2024-11-14</td><td><a href="https://arxiv.org/pdf/2411.18633v1.pdf" target="_blank" rel="noreferrer">下载</a></td><td>Broadband Internet access is an important way to help achieve the Sustainable Development Goals. Currently, fixed fiber infrastructure is essential for providing universal broadband, but has received ...</td></tr><tr><td><a href="https://arxiv.org/abs/2411.09380v1" target="_blank" rel="noreferrer">Connecting the Unconnected: A DT Case Study of Nomadic Nodes Deployment in Nepal</a></td><td>Ioannis Mavromatis, Angeliki Katsenou, Klodian Bardhi, Evangelos Xenos, Dimitra Simeonidou</td><td>2024-11-14</td><td><a href="https://arxiv.org/pdf/2411.09380v1.pdf" target="_blank" rel="noreferrer">下载</a></td><td>This paper addresses the challenge of robust cellular connectivity in dense, underdeveloped urban environments, specifically focusing on Kathmandu, Nepal.</td></tr><tr><td><a href="https://arxiv.org/abs/2411.09252v2" target="_blank" rel="noreferrer">Implementing an Optimized and Secured Multimedia Streaming Protocol in a Participatory Sensing Scenario</a></td><td>Andrea Vaiuso</td><td>2024-11-14</td><td><a href="https://arxiv.org/pdf/2411.09252v2.pdf" target="_blank" rel="noreferrer">下载</a></td><td>Multimedia streaming protocols are becoming increasingly popular in Crowdsensing due to their ability to deliver high-quality video content over the internet in real-time.</td></tr><tr><td><a href="https://arxiv.org/abs/2411.09148v1" target="_blank" rel="noreferrer">Toward Democratized Generative AI in Next-Generation Mobile Edge Networks</a></td><td>Ruichen Zhang, Jiayi He, Xiaofeng Luo, Dusit Niyato, Jiawen Kang, Zehui Xiong, Yonghui Li, Biplab Sikdar</td><td>2024-11-14</td><td><a href="https://arxiv.org/pdf/2411.09148v1.pdf" target="_blank" rel="noreferrer">下载</a></td><td>The rapid development of generative AI technologies, including large language models (LLMs), has brought transformative changes to various fields.</td></tr><tr><td><a href="https://arxiv.org/abs/2411.09134v1" target="_blank" rel="noreferrer">ABCI 3.0: Evolution of the leading AI infrastructure in Japan</a></td><td>Ryousei Takano, Shinichiro Takizawa, Yusuke Tanimura, Hidemoto Nakada, Hirotaka Ogawa</td><td>2024-11-14</td><td><a href="https://arxiv.org/pdf/2411.09134v1.pdf" target="_blank" rel="noreferrer">下载</a></td><td>ABCI 3.0 is the latest version of the ABCI, a large-scale open AI infrastructure that AIST has been operating since August 2018 and will be fully operational in January 2025. ABCI 3.</td></tr></tbody></table>',7)])])}const f=t(i,[["render",o]]);export{p as __pageData,f as default};
